/**
 * Vision Model Lookups
 *
 * Three separate vision model categories for bridging non-native modalities to text:
 * - ImageVisionModelId: models that can analyze images
 * - VideoVisionModelId: models that can analyze video
 * - AudioVisionModelId: models that can analyze audio/music
 *
 * Each is a TypeScript enum auto-generated from chatModelDefinitions inputs field.
 * Options are built by importing the enum members directly - no runtime iteration.
 *
 * Re-run: vibe update-all-model-prices or vibe gen
 */

import { z } from "zod";

import type { ModelOptionTokenBased } from "@/app/api/[locale]/agent/models/models";
import type { JwtPayloadType } from "@/app/api/[locale]/user/auth/types";
import { ModelSelectionType } from "../chat/skills/enum";
import {
  filterRoleModels,
  isModelOptionTokenBased,
  type ModelProviderEnvAvailability,
} from "../models/models";
import {
  filtersSelectionSchema,
  sharedFilterPropsSchema,
} from "../models/selection";

import { chatModelOptionsIndex } from "./models";

// Auto-generated enums - do not edit, regenerated by price updater
import {
  AudioVisionModelId,
  ImageVisionModelId,
  VideoVisionModelId,
} from "./vision-models.generated";

export { AudioVisionModelId, ImageVisionModelId, VideoVisionModelId };

// ============================================
// TYPED OPTION TYPES - one per vision modality
// ============================================

/** Token-based model that accepts image input. */
export type ImageVisionModelOption = ModelOptionTokenBased & {
  id: ImageVisionModelId;
};

/** Token-based model that accepts video input. */
export type VideoVisionModelOption = ModelOptionTokenBased & {
  id: VideoVisionModelId;
};

/** Token-based model that accepts audio input. */
export type AudioVisionModelOption = ModelOptionTokenBased & {
  id: AudioVisionModelId;
};

// ============================================
// OPTIONS INDEXES
// Built by directly looking up each enum value in chatModelOptionsIndex.
// ImageVisionModelId / VideoVisionModelId / AudioVisionModelId values are a strict
// subset of ChatModelId string values, so chatModelOptionsIndex[id] always resolves.
// ============================================

function makeImageVisionOption(
  id: ImageVisionModelId,
): ImageVisionModelOption | undefined {
  const opt = chatModelOptionsIndex[id];
  if (!opt || !isModelOptionTokenBased(opt)) {
    return undefined;
  }
  return { ...opt, id };
}

function makeVideoVisionOption(
  id: VideoVisionModelId,
): VideoVisionModelOption | undefined {
  const opt = chatModelOptionsIndex[id];
  if (!opt || !isModelOptionTokenBased(opt)) {
    return undefined;
  }
  return { ...opt, id };
}

function makeAudioVisionOption(
  id: AudioVisionModelId,
): AudioVisionModelOption | undefined {
  const opt = chatModelOptionsIndex[id];
  if (!opt || !isModelOptionTokenBased(opt)) {
    return undefined;
  }
  return { ...opt, id };
}

