export const imageVisionModelOptions: ImageVisionModelOption[] = Object.values(
  imageVisionModelOptionsIndex,
).filter((m): m is ImageVisionModelOption => m !== undefined);

export const videoVisionModelOptions: VideoVisionModelOption[] = Object.values(
  videoVisionModelOptionsIndex,
).filter((m): m is VideoVisionModelOption => m !== undefined);

export const audioVisionModelOptions: AudioVisionModelOption[] = Object.values(
  audioVisionModelOptionsIndex,
).filter((m): m is AudioVisionModelOption => m !== undefined);

// ============================================
// DROPDOWN OPTIONS
// ============================================

export const ImageVisionModelIdOptions = imageVisionModelOptions.map((m) => ({
  value: m.id,
  label: m.name,
}));

export const VideoVisionModelIdOptions = videoVisionModelOptions.map((m) => ({
  value: m.id,
  label: m.name,
}));

export const AudioVisionModelIdOptions = audioVisionModelOptions.map((m) => ({
  value: m.id,
  label: m.name,
}));

// ============================================
// GETTERS
// ============================================

